// --- HTMX progressive enhancement tests ---

#[tokio::test]
async fn htmx_toggle_returns_fragment_instead_of_redirect() {
    let app = spawn_app().await;
    let client =
        register_and_login(&app.address, "htmxtoggle@example.com", "securepassword123").await;

    // Add a todo
    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "HTMX toggle test")])
        .send()
        .await
        .expect("Failed to add todo");

    // Get the page to extract the todo ID
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to get todos page");
    let body = response.text().await.unwrap();
    let todo_id = extract_todo_id(&body);

    // Toggle with HX-Request header -- should return 200 with fragment, not 303 redirect
    let response = client
        .post(format!("{}/todos/{}/toggle", &app.address, todo_id))
        .header("HX-Request", "true")
        .send()
        .await
        .expect("Failed to toggle todo via HTMX");

    assert_eq!(
        response.status().as_u16(),
        200,
        "HTMX toggle should return 200, not redirect"
    );

    let body = response.text().await.unwrap();

    // Should return a single <li> fragment, not a full page
    assert!(
        body.contains("<li"),
        "HTMX toggle should return an <li> fragment"
    );
    assert!(
        !body.contains("<!DOCTYPE"),
        "HTMX toggle should NOT return a full HTML page"
    );
    assert!(
        body.contains("todo-item--completed"),
        "Toggled item should be marked completed in the fragment"
    );
    assert!(
        body.contains("HTMX toggle test"),
        "Fragment should contain the todo title"
    );
}

