    76→) -> Result<Response, TodosError> {
    77→    // Silently ignore empty/whitespace-only submissions per US-5
    78→    if form.title.trim().is_empty() {
    79→        return Ok(Redirect::to("/todos").into_response());
    80→    }
    81→
    82→    match add_todo(&pool, user_id.clone(), form.title).await {
    83→        Ok(_) => Ok(Redirect::to("/todos").into_response()),
    84→        Err(AddTodoError::InvalidTitle(title_err)) => {
    85→            let user_facing = match title_err {
    86→                crate::domain::TodoTitleError::Empty => {
    87→                    // Should not reach here due to empty check above, but handle gracefully
    88→                    return Ok(Redirect::to("/todos").into_response());
