use askama::Template;
use axum::extract::{Path, State};
use axum::http::{HeaderMap, StatusCode};
use axum::response::{Html, IntoResponse, Redirect, Response};
use axum::Form;
use sqlx::PgPool;
use uuid::Uuid;

use super::auth::AuthenticatedUser;
use crate::domain::{TodoItem, TodoItemId};
use crate::services::todo_service::{
    add_todo, delete_todo, get_todos, toggle_todo_completion, update_todo_title, AddTodoError,
    DeleteTodoError, ToggleTodoError, UpdateTitleError,
};

fn is_htmx_request(headers: &HeaderMap) -> bool {
    headers.contains_key("hx-request")
}

/// View model for a single todo item in the template.
pub struct TodoItemView {
    pub id: String,
    pub title: String,
    pub is_completed: bool,
}

impl From<&TodoItem> for TodoItemView {
    fn from(item: &TodoItem) -> Self {
        Self {
            id: item.id().as_uuid().to_string(),
            title: item.title().as_str().to_string(),
            is_completed: item.is_completed(),
        }
    }
}

#[derive(Template)]
#[template(path = "todos.html")]
pub struct TodosTemplate {
    pub todos: Vec<TodoItemView>,
    pub error_message: Option<String>,
}

#[derive(Template)]
#[template(path = "todo_item.html")]
pub struct TodoItemTemplate {
    pub todo: TodoItemView,
}

pub async fn get_todos_page(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
) -> Result<impl IntoResponse, TodosError> {
    let todos = get_todos(&pool, &user_id)
        .await
        .map_err(TodosError::Unexpected)?;

    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

    let template = TodosTemplate {
        todos: todo_views,
        error_message: None,
    };
    Ok(Html(template.render()?))
}

#[derive(serde::Deserialize)]
pub struct AddTodoForm {
    pub title: String,
}

pub async fn post_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Form(form): Form<AddTodoForm>,
) -> Result<Response, TodosError> {
    // Silently ignore empty/whitespace-only submissions per US-5
    if form.title.trim().is_empty() {
        return Ok(Redirect::to("/todos").into_response());
    }

    match add_todo(&pool, user_id.clone(), form.title).await {
        Ok(_) => Ok(Redirect::to("/todos").into_response()),
        Err(AddTodoError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => {
                    // Should not reach here due to empty check above, but handle gracefully
                    return Ok(Redirect::to("/todos").into_response());
                }
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };

            let todos = get_todos(&pool, &user_id)
                .await
                .map_err(TodosError::Unexpected)?;
            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();

            let template = TodosTemplate {
                todos: todo_views,
                error_message: Some(user_facing),
            };
            let body = template.render().map_err(TodosError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

pub async fn post_toggle_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match toggle_todo_completion(&pool, &todo_item_id, &user_id).await {
        Ok(_) => Ok(Redirect::to("/todos").into_response()),
        Err(ToggleTodoError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(ToggleTodoError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(ToggleTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

pub async fn post_delete_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match delete_todo(&pool, &todo_item_id, &user_id).await {
        Ok(()) => Ok(Redirect::to("/todos").into_response()),
        Err(DeleteTodoError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteTodoError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(DeleteTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

#[derive(Template)]
#[template(path = "edit_todo.html")]
pub struct EditTodoTemplate {
    pub todo_id: String,
    pub current_title: String,
    pub error_message: Option<String>,
}

pub async fn get_edit_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    let item = crate::infrastructure::todo_repository::find_todo_by_id(&pool, &todo_item_id)
        .await
        .map_err(|e| TodosError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;

    match item {
        Some(todo) if todo.user_id() == &user_id => {
            let template = EditTodoTemplate {
                todo_id: todo_id.to_string(),
                current_title: todo.title().as_str().to_string(),
                error_message: None,
            };
            Ok(Html(template.render()?).into_response())
        }
        Some(_) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        None => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
    }
}

#[derive(serde::Deserialize)]
pub struct EditTodoForm {
    pub title: String,
}

pub async fn post_edit_todo(
    AuthenticatedUser(user_id): AuthenticatedUser,
    State(pool): State<PgPool>,
    Path(todo_id): Path<Uuid>,
    Form(form): Form<EditTodoForm>,
) -> Result<Response, TodosError> {
    let todo_item_id = TodoItemId::from_uuid(todo_id);

    match update_todo_title(&pool, &todo_item_id, &user_id, form.title.clone()).await {
        Ok(()) => Ok(Redirect::to("/todos").into_response()),
        Err(UpdateTitleError::NotFound) => Ok((
            StatusCode::NOT_FOUND,
            Html("<h1>Todo not found</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateTitleError::Unauthorized) => Ok((
            StatusCode::FORBIDDEN,
            Html("<h1>Not authorized</h1>".to_string()),
        )
            .into_response()),
        Err(UpdateTitleError::InvalidTitle(title_err)) => {
            let user_facing = match title_err {
                crate::domain::TodoTitleError::Empty => "Title cannot be empty".to_string(),
                crate::domain::TodoTitleError::TooLong { max, .. } => {
                    format!("That title is too long (max {max} characters)")
                }
            };
            let template = EditTodoTemplate {
                todo_id: todo_id.to_string(),
                current_title: form.title,
                error_message: Some(user_facing),
            };
            let body = template.render().map_err(TodosError::Render)?;
            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
        }
        Err(UpdateTitleError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    }
}

#[derive(Debug, thiserror::Error)]
pub enum TodosError {
    #[error("Failed to render template")]
    Render(#[from] askama::Error),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

impl IntoResponse for TodosError {
    fn into_response(self) -> Response {
        tracing::error!(error = %self, "Todos error");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Html("<h1>Something went wrong</h1>".to_string()),
        )
            .into_response()
    }
}

// --- HTMX progressive enhancement tests ---

#[tokio::test]
async fn base_html_includes_htmx_script() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "htmxscript@example.com", "securepassword123").await;

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    let body = response.text().await.unwrap();
    assert!(
        body.contains("htmx.min.js"),
        "Base template should include the HTMX script"
    );
}

#[tokio::test]
async fn htmx_post_todo_returns_fragment_not_redirect() {
    let app = spawn_app().await;
    let client =
        register_and_login(&app.address, "htmx_add@example.com", "securepassword123").await;

    // POST with HX-Request header should return HTML fragment, not 303 redirect
    let response = client
        .post(format!("{}/todos", &app.address))
        .header("HX-Request", "true")
        .form(&[("title", "HTMX todo")])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        200,
        "HTMX add-todo should return 200 with HTML fragment, not redirect"
    );

    let body = response.text().await.unwrap();

    // Should return the new todo item as an <li> fragment, not a full page
    assert!(
        !body.contains("<!DOCTYPE html>"),
        "HTMX response should be a fragment, not a full page"
    );
    assert!(
        body.contains("HTMX todo"),
        "Fragment should contain the new todo item"
    );
    assert!(
        body.contains("todo-item"),
        "Fragment should contain a todo-item element"
    );
}

#[tokio::test]
async fn htmx_post_toggle_returns_updated_item_fragment() {
    let app = spawn_app().await;
    let client = register_and_login(
        &app.address,
        "htmxtoggle@example.com",
        "securepassword123",
    )
    .await;

    // Add a todo
    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Toggle via HTMX")])
        .send()
        .await
        .expect("Failed to add todo");

    // Get the todo ID
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to get todos page");
    let body = response.text().await.unwrap();
    let todo_id = extract_todo_id(&body);

    // Toggle with HX-Request header
    let response = client
        .post(format!("{}/todos/{}/toggle", &app.address, todo_id))
        .header("HX-Request", "true")
        .send()
        .await
        .expect("Failed to toggle todo");

    assert_eq!(
        response.status().as_u16(),
        200,
        "HTMX toggle should return 200 with fragment"
    );

    let body = response.text().await.unwrap();
    assert!(
        !body.contains("<!DOCTYPE html>"),
        "HTMX response should not contain full page"
    );
    assert!(
        body.contains("todo-item--completed"),
        "Toggled item should have completed class"
    );
    assert!(
        body.contains("Toggle via HTMX"),
        "Response should contain the item title"
    );
}

#[tokio::test]
async fn htmx_post_delete_returns_empty_body() {
    let app = spawn_app().await;
    let client =
        register_and_login(&app.address, "htmxdel@example.com", "securepassword123").await;

    // Add a todo
    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Delete via HTMX")])
        .send()
        .await
        .expect("Failed to add todo");

    // Get the todo ID
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to get todos page");
    let body = response.text().await.unwrap();
    let todo_id = extract_todo_id_from_delete(&body);

    // Delete with HX-Request header
    let response = client
        .post(format!("{}/todos/{}/delete", &app.address, todo_id))
        .header("HX-Request", "true")
        .send()
        .await
        .expect("Failed to delete todo");

    assert_eq!(
        response.status().as_u16(),
        200,
        "HTMX delete should return 200"
    );

    let body = response.text().await.unwrap();
    assert!(
        body.trim().is_empty(),
        "HTMX delete should return empty body to remove the element"
    );
}

